///|
pub(all) enum Source {
  File(String)
  Package(String)
} derive(Eq, Debug)

///|
pub fn Source::Source(text : String) -> Source {
  if text.has_prefix("pkg:") {
    Package(text)
  } else {
    File(text)
  }
}

///|
pub fn classify(source : Source) -> String {
  match source {
    File(path) => "file:\{path}"
    Package(name) => "package:\{name}"
  }
}

